package ssg
package js
package compress

import CompressTestHelper.{ AllOff, assertCompresses }
import ssg.js.compress.{ ToplevelConfig }

final class CompressBlockScopeSuite extends munit.FunSuite {

  override val munitTimeout = scala.concurrent.duration.Duration(120, "s")

  // =========================================================================
  // do_not_hoist_let
  // =========================================================================
  test("do_not_hoist_let".fail) {
    assertCompresses(
      input = """function x() {
            if (FOO) {
                let let1;
                let let2;
                var var1;
                var var2;
            }
        }""".stripMargin.trim,
      expected = """function x() {
            var var1, var2;
            if (FOO) {
                let let1;
                let let2;
            }
        }""".stripMargin.trim,
      options = AllOff.copy(
        hoistVars = true
      )
    )
  }

  // =========================================================================
  // drop_undefined_vardef
  // =========================================================================
  test("drop_undefined_vardef") {
    assertCompresses(
      input = """let x = undefined;
        const y = undefined""".stripMargin.trim,
      expected = """let x;
        const y = void 0""".stripMargin.trim,
      options = AllOff
    )
  }

  // =========================================================================
  // do_not_remove_anon_blocks_if_they_have_decls
  // =========================================================================
  test("do_not_remove_anon_blocks_if_they_have_decls") {
    assertCompresses(
      input = """function x() {
            {
                let x;
            }
            {
                var x;
            }
            {
                const y = 1;
                class Zee {};
            }
        }
        {
            let y;
        }
        {
            var y;
        }""".stripMargin.trim,
      expected = """function x(){
            {
                let x
            }
            var x;
            {
                const y = 1;
                class Zee {}
            }
        }
        {
            let y
        }
        var y""".stripMargin.trim,
      options = AllOff
    )
  }

  // =========================================================================
  // remove_unused_in_global_block
  // =========================================================================
  test("remove_unused_in_global_block".fail) {
    assertCompresses(
      input = """{
            let x;
            const y = 1;
            class Zee {};
            var w;
        }
        let ex;
        const why = 2;
        class Zed {};
        var wut;
        console.log(x, y, Zee)""".stripMargin.trim,
      expected = """var w;
        let ex;
        const why = 2;
        class Zed {};
        var wut;
        console.log(x, y, Zee)""".stripMargin.trim,
      options = AllOff.copy(
        unused = true
      )
    )
  }

  // =========================================================================
  // regression_block_scope_resolves
  // =========================================================================
  test("regression_block_scope_resolves".fail) {
    assertCompresses(
      input = """(function () {
            if (1) {
                let x;
                const y = 1;
                class Zee {};
            }
            if (1) {
                let ex;
                const why = 2;
                class Zi {};
            }
            console.log(typeof x, typeof y, typeof Zee, typeof ex, typeof why, typeof Zi);
        }())""".stripMargin.trim,
      expected = """(function () {
            if (1) {
                let e;
                const o = 1;
                class t {};
            }
            if (1) {
                let e;
                const o = 2;
                class t {};
            }
            console.log(typeof x, typeof y, typeof Zee, typeof ex, typeof why, typeof Zi);
        }())""".stripMargin.trim,
      options = AllOff.copy(
        deadCode = false
      )
    )
  }

  // =========================================================================
  // switch_block_scope_mangler
  // =========================================================================
  test("switch_block_scope_mangler".fail) {
    assertCompresses(
      input = """var fn = function(code) {
            switch (code) {
                case 1:
                    let apple = code + 1;
                    let dog = code + 4;
                    console.log(apple, dog);
                    break;
                case 2:
                    let banana = code + 2;
                    console.log(banana);
                    break;
                default:
                    let cat = code + 3;
                    console.log(cat);
            }
        };
        fn(1);
        fn(2);
        fn(3)""".stripMargin.trim,
      expected = """var fn = function(e) {
            switch (e) {
              case 1:
                let l = e + 1
                let o = e + 4;
                console.log(l, o);
                break;

              case 2:
                let n = e + 2;
                console.log(n);
                break;

              default:
                let c = e + 3;
                console.log(c);
            }
        };
        fn(1);
        fn(2);
        fn(3)""".stripMargin.trim,
      options = AllOff
    )
  }

  // =========================================================================
  // issue_334
  // =========================================================================
  test("issue_334".fail) {
    assertCompresses(
      input = """(function (A) {
            (function () {
                doPrint();
            })();

            function doPrint() {
                print(A);
            }
        }("Hello World!"));

        function print(A) {
            if (!A.x) {
                console.log(A);
            }
        }""".stripMargin.trim,
      expected = """(function (A) {
            A.x || console.log(A)
        }("Hello World!"))""".stripMargin.trim,
      options = AllOff.copy(
        toplevel = ToplevelConfig(funcs = true, vars = true)
      )
    )
  }

}
